ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name ?percentage_of_diabetics ?diabetic_count WHERE {
  ?diabetesdata a :DiabetesData .
  ?cities a :Cities .
  ?diabetesdata p:hasCities ?cities .
  ?cities p:name ?name .
  ?diabetesdata p:Percentage_Of_Diabetics ?percentage_of_diabetics .
  ?diabetesdata p:Diabetic_Count ?diabetic_count .
  ?diabetesdata p:Population ?population_o .
}
ORDER BY DESC(?population_o)
LIMIT 1 }
  component: { SELECT ?name ?diabetic_count WHERE {
  ?diabetesdata a :DiabetesData .
  ?cities a :Cities .
  ?diabetesdata p:hasCities ?cities .
  ?cities p:name ?name .
  ?diabetesdata p:Diabetic_Count ?diabetic_count .
  ?diabetesdata p:Population ?population_o .
}
ORDER BY DESC(?population_o)
LIMIT 1 }
  component_2: { SELECT ?name ?percentage_of_diabetics WHERE {
  ?diabetesdata a :DiabetesData .
  ?cities a :Cities .
  ?diabetesdata p:hasCities ?cities .
  ?cities p:name ?name .
  ?diabetesdata p:Percentage_Of_Diabetics ?percentage_of_diabetics .
  ?diabetesdata p:Population ?population_o .
}
ORDER BY DESC(?population_o)
LIMIT 1 }
}
